import { useEffect } from "react";

import "./App.css";
import SearchIcon from "./search.svg";

// 3782fe82
const API_URL = "http://www.omdbapi.com?apikey=3782fe82";

const movie1 = {
    "Title": "Deadpool",
    "Year": "2016",
    "imdbID": "tt1431045",
    "Type": "movie",
    "Poster": "https://m.media-amazon.com/images/M/MV5BYzE5MjY1ZDgtMTkyNC00MTMyLThhMjAtZGI5OTE1NzFlZGJjXkEyXkFqcGdeQXVyNjU0OTQ0OTY@._V1_SX300.jpg"
}

const App = () => {
    const searchMovies = async (title) => {
        const response = await fetch(`${API_URL}&s=${title}`);
        const data = await response.json();

        console.log(data.Search);
    }

    useEffect(() => {
        searchMovies("deadpool");
    }, [])

    return (
        <div className="app">
            <h1>MovieFox</h1>

            <div className="search">
                <input
                    placeholder="Enter Movie Name"
                    value="Deadpool"
                    onClick={() => { }}
                />
                <img
                    src={SearchIcon}
                    alt="search"
                />
            </div>

            <div className="container">
                <div className="movie">
                    <div>
                        <p>{movie1.year}</p>
                    </div>

                    <div>
                        <img src={movie1.Poster !== "N/A" ? movie1.Poster : "https://via.placeholder.com/400"} alt={movie1.Title}/>
                    </div>

                    <div>
                        <span>
                            {movie1.Type}
                        </span>
                        <h3>
                            {movie1.Title}
                        </h3>
                    </div>
                </div>
            </div>


        </div>
    )
}

export default App;
